import{_ as n,V as c,W as o,X as e,Y as a,Z as r,a1 as i,y as h}from"./framework.46148295.js";const g={},d=i('<h1 id="几种exchange模式" tabindex="-1"><a class="header-anchor" href="#几种exchange模式" aria-hidden="true">#</a> 几种Exchange模式</h1><p>AMQP协议中的核心思想就是生产者和消费者隔离，生产者从不直接将消息发送给队列。生产者通常不知道是否一个消息会被发送到队列中，只是将消息发送到一个交换机。先由Exchange来接收，然后Exchange按照特定的策略转发到Queue进行存储。同理，消费者也是如此。Exchange 就类似于一个交换机，分发发各个消息到相应的队列中。</p><p>RabbitMQ提供了四种Exchange模式：fanout、direct、topic、header。header模式在实际使用中较少，本文只对前三种模式进行比较。</p><h3 id="_1、fanout-exchange" tabindex="-1"><a class="header-anchor" href="#_1、fanout-exchange" aria-hidden="true">#</a> 1、Fanout Exchange</h3><p><img src="https://raw.githubusercontent.com/ifcoder/note/master/image/rabbitmq/FanoutExchange.png" alt="image" loading="lazy"><img src="https://raw.githubusercontent.com/ifcoder/note/master/image/rabbitmq/FanoutExchange2.png" alt="image" loading="lazy"></p><blockquote><p>所有发送到Fanout Exchange的消息都会被转发到与该Exchange 绑定(Binding)的所有Queue上。Fanout Exchange 不需要处理routing key 。只需要简单的将队列绑定到exchange上。这样发送到exchange的消息都会被转发到与该交换机绑定的所有队列上。类似子网广播，每台子网内的主机都获得了一份复制的消息。</p></blockquote><p>所以，Fanout Exchange 转发消息是最快的。</p><h3 id="_2、direct-exchange" tabindex="-1"><a class="header-anchor" href="#_2、direct-exchange" aria-hidden="true">#</a> 2、Direct Exchange</h3><p><img src="https://raw.githubusercontent.com/ifcoder/note/master/image/rabbitmq/DirectExchange.png" alt="image" loading="lazy"><img src="https://raw.githubusercontent.com/ifcoder/note/master/image/rabbitmq/DirectExchange2.png" alt="image" loading="lazy"></p><blockquote><p>所有发送到Direct Exchange的消息将会转发到被routing key绑定的Queue。<br> Direct模式可以使用RabbitMQ自带的Exchange：&quot; &quot;（default Exchange）。所以不需要将Exchange进行任何绑定(binding)操作。 消息传递时，routing key必须完全匹配，才会被队列接收，否则该消息会被抛弃。</p></blockquote><h3 id="_3、topic-exchange" tabindex="-1"><a class="header-anchor" href="#_3、topic-exchange" aria-hidden="true">#</a> 3、Topic Exchange</h3><p><img src="https://raw.githubusercontent.com/ifcoder/note/master/image/rabbitmq/TopicExchange.png" alt="image" loading="lazy"><img src="https://raw.githubusercontent.com/ifcoder/note/master/image/rabbitmq/TopicExchange2.png" alt="image" loading="lazy"></p><blockquote><p>所有发送到Topic Exchange的消息被转发到所有关心routing key中指定Topic的Queue上，Exchange 将routing key 和某Topic 进行模糊匹配。此时队列需要绑定一个Topic。<br><code>#</code>表示0个或若干个关键词，<code>*</code>表示一个关键词。如<code>log.*</code>能与<code>log.warn</code>匹配，无法与<code>log.warn.timeout</code>匹配；但是<code>log.#</code>能与上述两者匹配。</p></blockquote><p>所以，Topic Exchange 使用非常灵活。</p><h3 id="_4、headers-exchange" tabindex="-1"><a class="header-anchor" href="#_4、headers-exchange" aria-hidden="true">#</a> 4、Headers Exchange</h3><blockquote><p>Headers Exchange交换器允许匹配AMQP消息的header而非routing key。除此之外，Headers Exchange和Direct Exchange完全一致，但性能会差很多，因此他并不实用，而且几乎再也用不到了。</p></blockquote>',16),s={href:"http://www.rabbitmq.com/tutorials/tutorial-one-dotnet.html",target:"_blank",rel:"noopener noreferrer"},u=e("p",null,[e("strong",null,"性能排序：fanout > direct >> topic。比例大约为11：10：6")],-1);function l(p,x){const t=h("ExternalLinkIcon");return c(),o("div",null,[d,e("p",null,[a("这个是RabbitMQ 的实际使用的几个场景，熟悉了这个，基本上RabbitMQ也就了解了。"),e("a",s,[a("http://www.rabbitmq.com/tutorials/tutorial-one-dotnet.html"),r(t)])]),u])}const b=n(g,[["render",l],["__file","02.html.vue"]]);export{b as default};
